base_css:
body {
      margin: 0;
      font-family: 'DM Sans', -apple-system, BlinkMacSystemFont, "Segoe UI", sans-serif;
      background-color: var(--bg-body);
      color: var(--text);
      overflow-x: hidden;
      padding-top: var(--header-h);
    }
    @media (max-width: 991px) { body { padding-top: 64px; } }

    a { text-decoration: none; color: var(--primary); transition: color var(--t); }
    a:hover { color: var(--primary-2); }
    p { line-height: 1.7; color: var(--text-s); font-size: 0.95rem; }

    .font-syne { font-family: 'Syne', sans-serif; }

    /* ========================================================================== */
    /* COMPONENTS & TYPOGRAPHY                                                    */
    /* ========================================================================== */
    .section-title {
      position: relative; padding-bottom: .75rem; margin-bottom: 2rem;
      font-weight: 800; color: var(--primary-d); font-family: 'Syne', sans-serif;
      font-size: clamp(1.6rem, 4vw, 2.2rem);
    }
    .section-title::after {
      content: ''; position: absolute; bottom: 0; left: 0;
      width: 60px; height: 4px; border-radius: 2px;
      background: linear-gradient(90deg, var(--primary), var(--gold));
    }
    .section-title.center::after { left: 50%; transform: translateX(-50%); }

    /* ========================================================================== */
    /* HERO SECTION                                                               */
    /* ========================================================================== */
    .hero-banner {
      position: relative; overflow: hidden;
      background: linear-gradient(135deg, var(--digital-blue-950) 0%, var(--digital-blue-900) 50%, var(--digital-blue-800) 100%);
      padding: 80px 0 100px; text-align: center;
    }
    .hero-banner::before {
      content: ''; position: absolute; inset: 0;
      background-image: 
        radial-gradient(circle at 15% 50%, rgba(51, 133, 255, 0.2), transparent 30%),
        radial-gradient(circle at 85% 30%, rgba(51, 133, 255, 0.2), transparent 30%);
      z-index: 1; pointer-events: none;
    }
    .hero-ring {
      position: absolute; border-radius: 50%; border: 1px solid rgba(255,255,255,.05);
      pointer-events: none; z-index: 1;
    }
    .hero-ring-1 { width: 600px; height: 600px; top: -200px; left: -150px; border-color: rgba(51, 133, 255, 0.15); }
    .hero-ring-2 { width: 400px; height: 400px; bottom: -100px; right: -50px; border-color: rgba(255,255,255,.05); }

    .hero-content { position: relative; z-index: 3; max-width: 800px; margin: 0 auto; }
    .hero-breadcrumb {
      display: inline-flex; align-items: center; gap: 8px;
      color: var(--gold); font-size: .75rem; font-weight: 800; text-transform: uppercase; letter-spacing: 0.08em;
      background: rgba(51, 133, 255, 0.15); border: 1px solid rgba(51, 133, 255, 0.3);
      border-radius: 50px; padding: 6px 16px; margin-bottom: 24px;
      transition: all var(--t);
    }
    .hero-breadcrumb:hover { background: rgba(51, 133, 255, 0.25); color: #fff; transform: translateY(-2px); }
    .hero-banner h1 {
      font-size: clamp(2.5rem, 5vw, 3.8rem); font-weight: 800; color: #fff;
      letter-spacing: -.02em; margin-bottom: 16px; text-shadow: 0 4px 20px rgba(0,0,0,0.3);
    }
    .hero-banner p { font-size: 1.15rem; color: rgba(255,255,255,.75); line-height: 1.7; margin-bottom: 0; }

    /* ========================================================================== */
    /* FILTER & SEARCH BAR (Mobile Compatible)                                    */
    /* ========================================================================== */
    .controls-wrap {
      margin-top: -40px; position: relative; z-index: 10; margin-bottom: 40px;
      display: flex; flex-direction: column; align-items: center; gap: 20px;
    }
    .search-box { width: 100%; max-width: 500px; position: relative; }
    .search-box input {
      width: 100%; padding: 14px 24px 14px 48px; border-radius: 50px; border: 1px solid var(--bdr);
      background: #fff; box-shadow: var(--sh-md); font-family: inherit; font-size: .95rem;
      transition: all var(--t); outline: none;
    }
    .search-box input:focus { border-color: var(--primary); box-shadow: 0 8px 30px rgba(0,102,255,0.12); }
    .search-box i { position: absolute; left: 20px; top: 50%; transform: translateY(-50%); color: var(--text-m); font-size: 1.2rem; }

    /* Filter Wrapper & Arrows */
    .filter-wrapper {
      position: relative; width: 100%; display: flex; align-items: center; margin-bottom: 40px;
    }
    .filter-arrow {
      display: none; position: absolute; z-index: 20; top: 50%; transform: translateY(-50%);
      width: 36px; height: 36px; border-radius: 50%; background: #fff; border: 1px solid var(--bdr);
      box-shadow: var(--sh-md); color: var(--primary); align-items: center; justify-content: center;
      cursor: pointer; margin-top: -5px; transition: opacity 0.2s, background 0.2s;
    }
    .filter-arrow:hover { background: var(--sur-2); color: var(--primary-2); }
    .filter-arrow.left { left: 10px; opacity: 0; pointer-events: none; } 
    .filter-arrow.right { right: 10px; }

    .filter-wrapper::before, .filter-wrapper::after {
      content: ''; position: absolute; top: -10px; bottom: 15px; width: 50px;
      z-index: 15; pointer-events: none; display: none;
    }
    .filter-wrapper::before { left: 0; background: linear-gradient(to right, #fff 30%, transparent); }
    .filter-wrapper::after { right: 0; background: linear-gradient(to left, #fff 30%, transparent); }

    .filter-tabs { display: flex; flex-wrap: wrap; gap: 10px; justify-content: center; position: relative; z-index: 10; width: 100%; }
    .filter-tab {
      padding: 10px 22px; border-radius: 50px; background: #fff;
      border: 1px solid var(--bdr); font-weight: 700; font-size: .85rem;
      color: var(--text-m); cursor: pointer; transition: all var(--t);
      box-shadow: var(--sh-xs); display: flex; align-items: center; gap: 6px;
    }
    .filter-tab:hover { border-color: var(--primary-l); color: var(--primary); transform: translateY(-2px); box-shadow: var(--sh-sm); }
    .filter-tab.active {
      background: var(--primary); color: #fff; border-color: var(--primary);
      box-shadow: 0 6px 16px rgba(0,102,255,0.25); transform: translateY(-2px);
    }
    .filter-tab .badge { background: rgba(0,0,0,0.08); color: inherit; font-size: 0.7rem; padding: 2px 8px; border-radius: 50px; }
    .filter-tab.active .badge { background: rgba(255,255,255,0.2); color: #fff; }

    @media (max-width: 768px) {
      .filter-wrapper { width: 100vw; margin-left: calc(-50vw + 50%); margin-bottom: 24px; }
      .filter-wrapper::before, .filter-wrapper::after { display: block; }
      .filter-arrow { display: flex; }
      .filter-tabs {
        flex-wrap: nowrap !important; overflow-x: auto !important; justify-content: flex-start !important;
        padding: 5px 40px 15px 40px !important; margin-bottom: 0 !important;
        scrollbar-width: none; -webkit-overflow-scrolling: touch;
      }
      .filter-tabs::-webkit-scrollbar { display: none; }
      .filter-tab { flex: 0 0 auto !important; white-space: nowrap !important; padding: 8px 18px; font-size: 0.8rem; }
      .search-box input { font-size: 1rem; } 
    }

    /* ========================================================================== */
    /* PROJECT CARDS (Compact SaaS Design - 2 per row mobile)                     */
    /* ========================================================================== */
    .project-grid {
      display: grid;
      grid-template-columns: repeat(4, 1fr);
      gap: 20px;
      margin-bottom: 40px;
    }
    @media(max-width:1200px) { .project-grid { grid-template-columns: repeat(3, 1fr); } }
    @media(max-width:900px) { .project-grid { grid-template-columns: repeat(2, 1fr); } }

    .proj-card-wrap { animation: fadeInSlideUp 0.4s ease-out forwards; opacity: 0; }
    @keyframes fadeInSlideUp {
      from { opacity: 0; transform: translateY(20px); }
      to { opacity: 1; transform: translateY(0); }
    }

    .proj-card {
      background: #fff; border-radius: 12px; overflow: hidden;
      border: 1px solid rgba(0,0,0,0.06); box-shadow: var(--sh-sm);
      transition: transform 0.3s cubic-bezier(0.175, 0.885, 0.32, 1.275), box-shadow 0.3s ease;
      cursor: pointer; display: flex; flex-direction: column; height: 100%;
    }
    .proj-card:hover { transform: translateY(-8px); box-shadow: 0 16px 36px rgba(0,0,0,0.08); border-color: rgba(51,133,255,0.15); }

    .proj-top {
      height: 140px; display: flex; align-items: center; justify-content: center;
      font-size: 3.5rem; background-size: cover; background-position: center;
      background-color: var(--sur-2); border-bottom: 1px solid rgba(0,0,0,0.04);
      position: relative; overflow: hidden; transition: transform var(--t);
    }
    .proj-top img.proj-thumb {
      position: absolute; inset: 0; width: 100%; height: 100%; object-fit: cover;
      transition: opacity 0.3s, transform 0.5s ease; opacity: 1;
    }
    .proj-card:hover .proj-top img.proj-thumb { transform: scale(1.05); opacity: 0.8; }
    .proj-top .proj-emoji { position: relative; z-index: 2; transition: opacity 0.3s; }
    .proj-top.has-thumb .proj-emoji { display: none; }

    .proj-body { padding: 20px; display: flex; flex-direction: column; flex: 1; }
    .proj-badge {
      font-size: 0.65rem; font-weight: 800; color: var(--primary-d);
      background: var(--digital-blue-50); padding: 3px 10px; border-radius: 50px;
      text-transform: uppercase; letter-spacing: 0.05em; display: inline-block;
      margin-bottom: 10px; align-self: flex-start; border: 1px solid rgba(0,0,0,0.05);
    }
    .proj-title { font-family: 'DM Sans', sans-serif; font-size: 1.1rem; font-weight: 800; color: var(--primary-d); margin-bottom: 10px; line-height: 1.3; }

    .proj-meta-sm { display: flex; flex-direction: column; gap: 8px; font-size: 0.8rem; font-weight: 600; color: var(--text-m); margin-bottom: 16px; flex-grow: 1; }
    .proj-meta-sm span { display: flex; align-items: flex-start; gap: 6px; line-height: 1.4; }
    .proj-meta-sm i { color: var(--primary); font-size: 0.95rem; flex-shrink: 0; margin-top: 1px; }

    .proj-action {
      margin-top: auto; font-size: 0.8rem; color: var(--primary); font-weight: 700;
      display: flex; align-items: center; gap: 6px;
      border-top: 1px solid var(--bdr-s); padding-top: 12px; transition: gap 0.2s;
    }
    .proj-card:hover .proj-action { gap: 10px; color: var(--primary-2); }

    .no-results, .loading-state {
      grid-column: 1 / -1; text-align: center; padding: 60px 20px;
      background: #fff; border-radius: var(--r-xl); border: 1px dashed var(--bdr);
    }
    .no-results i, .loading-state .spinner-border { font-size: 3rem; color: var(--text-m); display: block; margin: 0 auto 16px; opacity: 0.6; }
    .loading-state .spinner-border { border-width: 0.3em; opacity: 1; color: var(--primary) !important;}

    @media (max-width: 768px) {
      .project-grid { grid-template-columns: repeat(2, 1fr); gap: 12px; margin-bottom: 32px; }
      .proj-body { padding: 12px; }
      .proj-title { font-size: 0.95rem; margin-bottom: 8px; line-height: 1.3; }
      .proj-top { height: 100px; font-size: 2rem; }
      .proj-badge { font-size: 0.6rem; padding: 3px 8px; margin-bottom: 8px; }
      .proj-meta-sm { font-size: 0.7rem; gap: 6px; margin-bottom: 12px; }
      .proj-meta-sm i { font-size: 0.85rem; }
      .proj-action { font-size: 0.75rem; padding-top: 10px; }
      .proj-action i { font-size: 0.9rem; }
    }

    /* ========================================================================== */
    /* SPLIT-LAYOUT MODAL                                                         */
    /* ========================================================================== */
    .proj-modal-overlay {
      display: none; position: fixed; inset: 0; background: rgba(0,14,36,0.65);
      z-index: 10000; align-items: center; justify-content: center; padding: 20px;
      backdrop-filter: blur(6px); -webkit-backdrop-filter: blur(6px);
    }
    .proj-modal-overlay.open { display: flex; }

    .proj-modal {
      width: 960px; max-width: 100%; background: #fff; border-radius: 24px;
      overflow: hidden; box-shadow: 0 24px 60px rgba(0,0,0,0.2);
      animation: modalPop 0.3s cubic-bezier(0.175, 0.885, 0.32, 1.275);
      display: flex; flex-direction: row; position: relative;
    }
    @keyframes modalPop {
      from { transform: scale(0.92); opacity: 0; }
      to { transform: scale(1); opacity: 1; }
    }

    .proj-m-close {
      position: absolute; top: 16px; right: 16px; width: 40px; height: 40px; border-radius: 50%;
      background: rgba(255,255,255,0.85); color: var(--text-s); border: none;
      display: flex; align-items: center; justify-content: center; cursor: pointer;
      font-size: 1.2rem; z-index: 30; transition: all 0.2s; box-shadow: var(--sh-sm);
      backdrop-filter: blur(4px); -webkit-backdrop-filter: blur(4px);
    }
    .proj-m-close:hover { background: #fff; color: var(--error); transform: scale(1.1); }

    /* LEFT SIDE: Visual Thumbnail & Links */
    .proj-m-left-panel {
      width: 45%; position: relative; display: flex; flex-direction: column;
      border-right: 1px solid var(--bdr-s); order: 1; background-color: var(--primary-l);
      overflow: hidden;
    }
    .proj-m-visual {
      flex: 1; position: relative;
      display: flex; align-items: center; justify-content: center; font-size: 6rem;
      transition: background-color 0.3s ease; overflow: hidden; min-height: 200px;
    }
    .proj-m-visual::after {
      content: ''; position: absolute; inset: 0;
      box-shadow: inset -10px 0 20px rgba(0,0,0,0.06); pointer-events: none; z-index: 10;
    }
    .proj-m-visual img {
      position: absolute; inset: 0; width: 100%; height: 100%; object-fit: cover; z-index: 2;
    }
    .proj-carousel-wrap {
      position: absolute; inset: 0; width: 100%; height: 100%; z-index: 2;
    }
    .carousel-control-prev, .carousel-control-next { z-index: 15; width: 10%; opacity: 0.8; }
    .carousel-control-prev:hover, .carousel-control-next:hover { opacity: 1; }
    .carousel-control-prev-icon, .carousel-control-next-icon {
      width: 2.5rem; height: 2.5rem; filter: drop-shadow(0 2px 6px rgba(0,0,0,0.9));
    }
    .m-emoji-overlay {
      position: absolute; inset: 0; display: flex; align-items: center; justify-content: center;
      z-index: 1; color: #fff; text-shadow: 0 4px 20px rgba(0,0,0,0.2);
    }

    .m-resource-links-wrap {
      width: 100%; padding: 24px;
      background: rgba(255, 255, 255, 0.95);
      backdrop-filter: blur(8px);
      -webkit-backdrop-filter: blur(8px);
      border-top: 1px solid var(--bdr-s);
      z-index: 20;
    }

    /* RIGHT SIDE: Content */
    .proj-m-body-wrapper {
      width: 55%; background: #fff; display: flex; flex-direction: column;
      max-height: 85vh; position: relative; order: 2; min-height: 0;
    }
    .proj-m-header {
      padding: 24px 32px 12px 32px; border-bottom: 1px solid var(--bdr-s);
      background: #fff; position: relative; flex-shrink: 0;
    }
    .proj-m-title {
      font-size: 1.35rem; font-weight: 800; color: var(--primary-d);
      margin: 8px 0 4px 0; line-height: 1.25; font-family: 'DM Sans', sans-serif;
    }
    .m-by { font-size: 0.85rem; font-weight: 700; color: var(--primary); display: flex; align-items: center; gap: 8px; }

    .proj-m-content {
      padding: 16px 32px 24px 32px; overflow-y: auto; flex-grow: 1; min-height: 0;
    }
    .proj-m-desc {
      font-size: 0.85rem; color: var(--text-s); line-height: 1.6; margin-bottom: 20px;
    }
    .proj-m-list { list-style: none; padding: 0; margin: 0 0 20px 0; }
    .proj-m-list li {
      display: flex; align-items: flex-start; gap: 12px;
      padding: 12px 0; border-bottom: 1px solid var(--bdr-s);
    }
    .proj-m-list li:last-child { border-bottom: none; padding-bottom: 0; }
    .proj-m-icon {
      width: 36px; height: 36px; border-radius: 10px;
      background: var(--digital-blue-50); color: var(--digital-blue-600);
      display: flex; align-items: center; justify-content: center;
      font-size: 1rem; flex-shrink: 0; border: 1px solid rgba(0,102,255,0.05);
    }
    .proj-m-info { display: flex; flex-direction: column; gap: 2px; }
    .proj-m-label {
      font-size: 0.65rem; font-weight: 800; letter-spacing: 0.05em;
      text-transform: uppercase; color: var(--text-m);
    }
    .proj-m-val { font-size: 0.85rem; font-weight: 600; color: var(--primary-d); line-height: 1.4; }

    .m-tags-wrap { display: flex; flex-wrap: wrap; gap: 6px; margin-bottom: 8px; }
    .m-tag { font-size: 0.65rem; font-weight: 800; padding: 4px 10px; border-radius: 50px; background: var(--sur-2); color: var(--text-s); border: 1px solid var(--bdr); text-transform: uppercase; }

    /* Resource Links in Modal (Square Boxes Fit-to-Row Fix) */
    #mLinksList {
      display: flex !important;
      gap: 8px;
      flex-wrap: wrap;
    }
    .m-resource-link {
      display: flex; flex-direction: column; align-items: center; justify-content: center; text-align: center;
      padding: 10px 4px; background: var(--sur-2); border: 1px solid var(--bdr-s);
      border-radius: 12px; transition: all var(--t); text-decoration: none; color: var(--text-s);
      box-shadow: var(--sh-xs); 
      aspect-ratio: 1;
      flex: 1 1 0; 
      min-width: 70px; 
      max-width: 95px; 
    }
    .m-resource-link:hover { background: #fff; border-color: var(--primary-l); box-shadow: var(--sh-sm); transform: translateY(-4px); color: var(--primary-2); }

    .rl-icon-box {
      width: 32px; height: 32px; border-radius: 8px;
      display: flex; align-items: center; justify-content: center; font-size: 1.1rem;
      border: 1px solid var(--bdr-s); color: #fff; margin-bottom: 6px;
      transition: transform var(--t);
    }
    .m-resource-link:hover .rl-icon-box { transform: scale(1.1); }

    .rl-github .rl-icon-box { background: #1d4ed8; border-color: #1d4ed8;}
    .rl-linkedin .rl-icon-box { background: #0077b5; border-color: #0077b5;}
    .rl-video .rl-icon-box { background: #be123c; border-color: #be123c;}
    .rl-ppt .rl-icon-box { background: #c2410c; border-color: #c2410c;}

    .m-rl-title { font-weight: 800; font-size: 0.68rem; color: var(--primary-d); display: block; line-height: 1.2; margin-bottom: 2px; }
    .m-rl-sub { font-size: 0.55rem; color: var(--text-m); display: block; line-height: 1.2; }

    /* VIDEO EMBED */
    .m-video-section { margin-bottom: 20px; }
    .m-video-section h5 { font-size: 0.7rem; font-weight: 800; text-transform: uppercase; letter-spacing: 0.08em; color: var(--text-m); margin-bottom: 8px; }
    .m-video-frame {
      width: 100%; aspect-ratio: 16/9; border-radius: 12px;
      background: var(--digital-blue-950); display: flex; align-items: center; justify-content: center;
      overflow: hidden; position: relative; border: 1px solid var(--bdr);
    }
    .m-video-frame iframe { width: 100%; height: 100%; border: none; }

    /* ========================================================================== */
    /* RESPONSIVE DESIGN (Mobile Specific Enhancements)                           */
    /* ========================================================================== */
    @media (max-width: 768px) {
      .project-grid { grid-template-columns: repeat(2, 1fr); gap: 12px; margin-bottom: 32px; }
      .proj-body { padding: 12px; }
      .proj-title { font-size: 0.95rem; margin-bottom: 8px; line-height: 1.3; }
      .proj-top { height: 100px; font-size: 2rem; }
      .proj-badge { font-size: 0.6rem; padding: 3px 8px; margin-bottom: 8px; }
      .proj-meta-sm { font-size: 0.7rem; gap: 6px; margin-bottom: 12px; }
      .proj-meta-sm i { font-size: 0.85rem; }
      .proj-action { font-size: 0.75rem; padding-top: 10px; }
      .proj-action i { font-size: 0.9rem; }

      /* ══ Native Full Scroll for Mobile Modal ══ */
      .proj-modal { 
        display: block; 
        width: 95%; border-radius: 16px; 
        height: 85vh; max-height: 85vh; 
        overflow-y: auto; 
        -webkit-overflow-scrolling: touch;
      }

      .proj-m-left-panel { width: 100%; display: block; border-right: none; border-bottom: 1px solid var(--bdr-s); }
      .proj-m-visual { min-height: 160px; height: 160px; font-size: 4rem; }
      .proj-m-visual::after { display: none; }

      .m-resource-links-wrap { padding: 12px 16px; }
      .m-resource-links-wrap h4 { width: 100%; margin-bottom: 8px !important; font-size: 0.85rem !important; }

      #mLinksList { grid-template-columns: repeat(auto-fill, minmax(80px, 1fr)) !important; gap: 8px; }
      .m-resource-link { padding: 8px 4px; border-radius: 10px; max-width: 100px; }
      .rl-icon-box { width: 28px; height: 28px; font-size: 1rem; margin-bottom: 6px; border-radius: 6px; }
      .m-rl-title { font-size: 0.65rem; margin-bottom: 2px; }
      .m-rl-sub { font-size: 0.55rem; display: -webkit-box; -webkit-line-clamp: 1; -webkit-box-orient: vertical; overflow: hidden; }

      .proj-m-body-wrapper { width: 100%; padding: 0; display: block; overflow: visible; position: static; }
      .proj-m-header { padding: 16px 20px 8px 20px; }
      .proj-m-content { padding: 8px 20px 24px 20px; overflow-y: visible; }

      .proj-m-title { font-size: 1.15rem; margin-bottom: 4px; padding-right: 30px; }
      .m-by { font-size: 0.8rem; margin-bottom: 0; }

      .proj-m-close { 
        top: 10px; right: 10px; width: 30px; height: 30px; font-size: 1rem; 
        background: rgba(255,255,255,0.9); box-shadow: 0 2px 8px rgba(0,0,0,0.15);
      }
    }

    /* ========================================================================== */
    /* ANIMATIONS                                                                 */
    /* ========================================================================== */
    .fade-up { opacity: 0; transform: translateY(32px); transition: opacity .6s var(--ease), transform .6s var(--ease); }
    .fade-up.visible { opacity: 1; transform: translateY(0); }
    .fade-in { opacity: 0; transition: opacity .6s var(--ease); }
    .fade-in.visible { opacity: 1; }
    .delay-1 { transition-delay: .05s; }
    .delay-2 { transition-delay: .1s; }

