(function () {
    'use strict';

    let currentCategory = 'all';
    let allProjects = [];

    const API_KEY = '50904e3e69c5ce20fbc3ce0e881bcdac42c5a64cedaafd03614b8d0cb2eef29c';
    const API_URL = `https://gpnainital.com/api/data/projects?key=${API_KEY}`;

    // Map for department colors
    const deptColors = {
      'it': '#1d4ed8', 'mech': '#d97706', 'mechanical': '#d97706', 'civil': '#9333ea',
      'elec': '#059669', 'electrical': '#059669', 'elx': '#db2777', 'electronics': '#db2777', 
      'pharm': '#be123c', 'pharmacy': '#be123c', 'general': '#3385ff'
    };

    function sanitizeUrl(url) {
      if (!url) return '';
      return url.replace(/http:\/\/192\.168\.1\.2:8000/gi, 'https://gpnainital.com');
    }

    /* ── Safely parse images whether they are Strings, Arrays, or JSON ── */
    function parseImages(imgData) {
      if (!imgData) return [];

      if (Array.isArray(imgData)) {
        return imgData;
      }

      if (typeof imgData === 'string') {
        const trimmed = imgData.trim();
        if (trimmed === '') return [];

        try {
          const parsed = JSON.parse(trimmed);
          return Array.isArray(parsed) ? parsed : [trimmed];
        } catch (e) {
          // If it fails to parse as JSON, treat it as a single URL string
          return [trimmed];
        }
      }

      return [];
    }

    /* ── 1. Scroll Reveal ── */
    const revealEls = document.querySelectorAll('.fade-up, .fade-in');
    if (revealEls.length) {
      const obs = new IntersectionObserver(entries => {
        entries.forEach(e => { if (e.isIntersecting) { e.target.classList.add('visible'); obs.unobserve(e.target); } });
      }, { threshold: 0.1 });
      revealEls.forEach(el => obs.observe(el));
    }

    /* ── 2. Fetch Projects API ── */
    async function fetchProjects() {
      const loader = document.getElementById('loadingProjects');
      const noRes = document.getElementById('noResults');

      try {
        const res = await fetch(API_URL);
        if (!res.ok) throw new Error('API Error');
        const json = await res.json();
        allProjects = json.data || json.records || [];

        if (loader) loader.style.display = 'none';

        if (allProjects.length > 0) {
          generateFilters(allProjects);
          renderProjects(allProjects);
          initFilterScroll();

          // Trigger "all" filter to begin staggered animation
          const allBtn = document.querySelector('.filter-tab[data-cat="all"]');
          if (allBtn) allBtn.click();
        } else {
          if (noRes) noRes.style.display = 'block';
        }
      } catch (err) {
        console.error("Failed to fetch projects:", err);
        if (loader) loader.style.display = 'none';
        if (noRes) {
          noRes.querySelector('h4').textContent = "Failed to load projects";
          noRes.querySelector('p').textContent = "Please try refreshing the page later.";
          noRes.style.display = 'block';
        }
      }
    }

    /* ── 3. Render Filters ── */
    function generateFilters(projects) {
      const filterContainer = document.getElementById('filterTabs');
      const categories = new Map();

      projects.forEach(p => {
        const cat = p.category || p.department_key || 'general';
        const deptName = p.department || 'General';
        categories.set(cat, deptName);
      });

      let html = `<button class="filter-tab active" data-cat="all" onclick="window.setCategory('all', this)">All Projects <span class="badge">${projects.length}</span></button>`;

      categories.forEach((name, key) => {
        const count = projects.filter(p => (p.category || p.department_key || 'general') === key).length;
        let shortName = name;
        if(name.includes('Information')) shortName = 'IT';
        else if(name.includes('Mechanical')) shortName = 'Mechanical';
        else if(name.includes('Civil')) shortName = 'Civil';
        else if(name.includes('Electrical')) shortName = 'Electrical';
        else if(name.includes('Electronics')) shortName = 'Electronics';

        html += `<button class="filter-tab" data-cat="${key}" onclick="window.setCategory('${key}', this)">
                   ${shortName} <span class="badge">${count}</span>
                 </button>`;
      });

      filterContainer.innerHTML = html;
    }

    /* ── 4. Init Filter Scroll Arrows ── */
    function initFilterScroll() {
      const container = document.getElementById('filterTabs');
      const leftBtn = document.getElementById('filterArrowLeft');
      const rightBtn = document.getElementById('filterArrowRight');
      if(!container || !leftBtn || !rightBtn) return;

      const updateArrows = () => {
        if (window.innerWidth > 768) {
          leftBtn.style.opacity = '0'; rightBtn.style.opacity = '0';
          leftBtn.style.pointerEvents = 'none'; rightBtn.style.pointerEvents = 'none';
          return;
        }
        const scrollLeft = container.scrollLeft;
        const maxScroll = container.scrollWidth - container.clientWidth;

        leftBtn.style.opacity = scrollLeft > 5 ? '1' : '0';
        leftBtn.style.pointerEvents = scrollLeft > 5 ? 'auto' : 'none';

        rightBtn.style.opacity = scrollLeft < maxScroll - 5 ? '1' : '0';
        rightBtn.style.pointerEvents = scrollLeft < maxScroll - 5 ? 'auto' : 'none';
      };

      container.addEventListener('scroll', updateArrows);
      window.addEventListener('resize', updateArrows);

      leftBtn.addEventListener('click', () => container.scrollBy({ left: -150, behavior: 'smooth' }));
      rightBtn.addEventListener('click', () => container.scrollBy({ left: 150, behavior: 'smooth' }));
      setTimeout(updateArrows, 150);
    }

    /* ── 5. Render Projects ── */
    function renderProjects(projects) {
      const grid = document.getElementById('projectGrid');
      grid.querySelectorAll('.proj-card-wrap').forEach(el => el.remove());

      projects.forEach((p, index) => {
        const cat = p.category || p.department_key || 'general';
        let bg = deptColors['general'];
        for (const [key, color] of Object.entries(deptColors)) {
          if (cat.toLowerCase().includes(key)) { bg = color; break; }
        }

        const rawImageUrl = p.image_url || p.images || p.thumb;
        let images = parseImages(rawImageUrl).map(img => sanitizeUrl(img));
        const coverImg = images.length > 0 ? images[0] : '';

        const wrap = document.createElement('div');
        wrap.className = 'proj-card-wrap';
        wrap.setAttribute('data-cat', cat);
        wrap.style.display = 'none';

        const title = p.title || 'Untitled Project';
        const department = p.department || 'General';
        const year = p.year || 'N/A';
        const tags = p.tags ? p.tags.split(',')[0] : 'Tech';
        const emoji = p.emoji || '🚀';

        const modalData = {
          title: title,
          department: department,
          emoji: emoji,
          by: p.by || p.team || 'Student Team',
          desc: p.description || p.desc || 'No description available.',
          guide: p.guide || 'N/A',
          year: year,
          tags: p.tags || '',
          github: p.github || p.github_url || '',
          linkedin: p.linkedin || p.linkedin_url || '',
          video: p.video || p.video_url || '',
          ppt: p.ppt || p.document_url || '',
          images: rawImageUrl
        };

        wrap.innerHTML = `
          <div class="proj-card" onclick='window.openProjectModal(${JSON.stringify(modalData).replace(/'/g, "&#39;")}, "${bg}")'>
            <div class="proj-top" style="background-color: ${bg};">
               ${coverImg ? `<img src="${coverImg}" class="proj-thumb" alt="${title}">` : ''}
               ${!coverImg ? `<span class="proj-emoji">${emoji}</span>` : ''}
            </div>
            <div class="proj-body">
              <span class="proj-badge" style="color:${bg}; background:${bg}15; border-color:${bg}30;">${department}</span>
              <h3 class="proj-title">${title}</h3>

              <div class="proj-meta-sm">
                <span><i class="bi bi-calendar3"></i> <span>${year}</span></span>
                <span><i class="bi bi-cpu"></i> <span>${tags}</span></span>
              </div>

              <div class="proj-action"><i class="bi bi-eye"></i> View Details</div>
            </div>
          </div>
        `;
        grid.insertBefore(wrap, document.getElementById('noResults'));
      });
    }

    /* ── 6. Filtering Logic ── */
    window.setCategory = function(cat, btn) {
      document.querySelectorAll('.filter-tab').forEach(b => b.classList.remove('active'));
      btn.classList.add('active');
      currentCategory = cat;

      if(window.innerWidth <= 768) {
        const container = document.getElementById('filterTabs');
        const scrollTarget = btn.offsetLeft - container.offsetWidth / 2 + btn.offsetWidth / 2;
        container.scrollTo({ left: scrollTarget, behavior: 'smooth' });
      }
      window.filterProjects();
    };

    window.filterProjects = function() {
      const query = document.getElementById('projectSearch').value.toLowerCase();
      const wrappers = document.querySelectorAll('.proj-card-wrap');
      let count = 0;

      wrappers.forEach(wrap => {
        const card = wrap.querySelector('.proj-card');
        const textContent = card.innerText.toLowerCase();
        const cat = wrap.dataset.cat;
        const matchCat = (currentCategory === 'all' || cat === currentCategory);
        const matchQuery = (!query || textContent.includes(query));

        if (matchCat && matchQuery) {
          wrap.style.display = 'block';
          wrap.style.animation = 'none';
          void wrap.offsetWidth;
          wrap.style.animation = `fadeInSlideUp 0.4s ease-out forwards`;
          wrap.style.animationDelay = `${(count % 6) * 0.05}s`;
          count++;
        } else {
          wrap.style.display = 'none';
        }
      });

      document.getElementById('noResults').style.display = (count === 0) ? 'block' : 'none';
    };

    /* ── 7. Modal Logic ── */
    window.openProjectModal = function(p, bg) {
      const overlay = document.getElementById('projModalOverlay');
      const visualEl = document.getElementById('mVisual');
      const leftPanel = document.getElementById('mLeftPanel');
      const carouselEl = document.getElementById('projCarousel');
      const carouselInner = document.getElementById('projCarouselInner');
      const emojiOverlay = document.getElementById('mEmoji');
      const carouselControls = document.querySelectorAll('#projCarousel .carousel-control-prev, #projCarousel .carousel-control-next');

      visualEl.style.backgroundColor = bg;
      leftPanel.style.backgroundColor = `${bg}15`; 

      const rawImageUrl = p.images || p.image_url || p.thumb;
      let images = parseImages(rawImageUrl).map(img => sanitizeUrl(img));

      if (images.length > 0) {
          let html = '';
          images.forEach((img, i) => {
              html += `
              <div class="carousel-item h-100 ${i === 0 ? 'active' : ''}" style="position:relative; overflow:hidden; background-color:#000;">
                  <div style="position:absolute; inset:-20px; background-image:url('${img}'); background-size:cover; background-position:center; filter:blur(15px); opacity:0.6;"></div>
                  <img src="${img}" class="d-block w-100 h-100" style="object-fit:contain; position:relative; z-index:2;" alt="Project Image">
              </div>`;
          });
          carouselInner.innerHTML = html;
          carouselEl.style.display = 'block';
          emojiOverlay.style.display = 'none';
          visualEl.style.backgroundColor = '#000';

          carouselControls.forEach(c => c.style.display = images.length > 1 ? 'flex' : 'none');
      } else {
          carouselEl.style.display = 'none';
          emojiOverlay.style.display = 'flex';
          emojiOverlay.textContent = p.emoji || '🚀';
          visualEl.style.backgroundColor = bg;
      }

      const badge = document.getElementById('mDeptBadge');
      badge.textContent = p.department || 'Project';
      badge.style.color = bg;
      badge.style.backgroundColor = `${bg}15`;
      badge.style.borderColor = `${bg}30`;

      document.getElementById('mTitle').textContent = p.title || '–';
      document.getElementById('mBy').innerHTML = `<i class="bi bi-people-fill"></i> ${p.by || 'Student Team'}`;
      document.getElementById('mDesc').textContent = p.desc || 'No description available.';
      document.getElementById('mGuide').textContent = p.guide || 'N/A';
      document.getElementById('mYear').textContent = p.year || '–';

      const tagsWrap = document.getElementById('mTags');
      if(p.tags) {
         tagsWrap.innerHTML = p.tags.split(',').map(t => `<span class="m-tag">${t.trim()}</span>`).join('');
      } else {
         tagsWrap.innerHTML = '';
      }

      const videoSection = document.getElementById('mVideoSection');
      const videoFrame   = document.getElementById('mVideoFrame');
      if (p.video && p.video.trim() !== '') {
        videoSection.style.display = 'block';
        const isEmbed = p.video.includes('/embed/');
        const embedUrl = isEmbed ? p.video : p.video.replace('watch?v=', 'embed/');
        videoFrame.innerHTML = `<iframe src="${embedUrl}" allow="accelerometer; autoplay; clipboard-write; encrypted-media; gyroscope; picture-in-picture" allowfullscreen></iframe>`;
      } else {
        videoSection.style.display = 'none';
        videoFrame.innerHTML = '';
      }

      const linkContainer = document.getElementById('mResourceLinks');
      const linkList = document.getElementById('mLinksList');
      linkList.innerHTML = '';
      let hasLinks = false;

      function makeLink(href, cls, icon, label, sublabel) {
        if (href && href.trim() !== '') {
          hasLinks = true;
          linkList.innerHTML += `<a href="${href}" target="_blank" rel="noopener" class="m-resource-link ${cls}">
              <div class="rl-icon-box"><i class="bi bi-${icon}"></i></div>
              <span class="m-rl-title">${label}</span>
              <span class="m-rl-sub">${sublabel}</span>
          </a>`;
        }
      }

      makeLink(p.github, 'rl-github', 'github',         'Source Code', 'Repository');
      makeLink(p.linkedin,'rl-linkedin','linkedin',     'LinkedIn',    'Profile');
      makeLink(p.video,  'rl-video',  'play-circle-fill','Demo Video',  'YouTube');
      makeLink(p.ppt,    'rl-ppt',    'easel-fill',      'Presentation','Slides');

      if(hasLinks) {
         linkContainer.style.display = 'block';
      } else {
         linkContainer.style.display = 'none';
      }

      overlay.classList.add('open');
      document.body.style.overflow = 'hidden';
    };

    const overlay = document.getElementById('projModalOverlay');
    function closeModal() {
      overlay.classList.remove('open');
      document.body.style.overflow = '';
      const iframe = document.querySelector('#mVideoFrame iframe');
      if (iframe) { const s = iframe.src; iframe.src = ''; iframe.src = s; }
    }

    document.getElementById('mCloseFloating').addEventListener('click', closeModal);
    overlay.addEventListener('click', e => { if (e.target === overlay) closeModal(); });
    document.addEventListener('keydown', e => { if (e.key === 'Escape') closeModal(); });

    /* ── INIT ── */
    document.addEventListener('DOMContentLoaded', () => {
      fetchProjects();
    });

  })();
